    private static string BuildDynamicQuery(
        string tableName, 
        Dictionary<string, string> filters, 
        List<string> columns,
        string orderBy,
        int limit)
    {
        var query = new StringBuilder();
        
        string selectClause = columns.Count > 0 
            ? string.Join(", ", columns) 
            : "*";
        
        query.Append($"SELECT TOP {limit} {selectClause} FROM {tableName}");
        
        if (filters.Count > 0)
        {
            query.Append(" WHERE ");
            var whereClauses = new List<string>();
            
            foreach (var filter in filters)
            {
                string columnName = filter.Key;
                string value = filter.Value;
                
                if (value.Contains(","))
                {
                    var values = value.Split(',');
                    var inValues = new List<string>();
                    foreach (var v in values)
                    {
                        inValues.Add($"'{v.Replace("'", "''")}'");
                    }
                    whereClauses.Add($"{columnName} IN ({string.Join(", ", inValues)})");
                }
                else if (value.StartsWith(">") || value.StartsWith("<") || value.StartsWith(">=") || value.StartsWith("<="))
                {
                    string op = value.StartsWith(">=") || value.StartsWith("<=") ? value.Substring(0, 2) : value.Substring(0, 1);
                    string val = value.Substring(op.Length);
                    whereClauses.Add($"{columnName} {op} '{val.Replace("'", "''")}'");
                }
                else if (value.Contains("*") || value.Contains("%"))
                {
                    string likeValue = value.Replace("*", "%").Replace("'", "''");
                    whereClauses.Add($"{columnName} LIKE '{likeValue}'");
                }
                else
                {
                    whereClauses.Add($"{columnName} = '{value.Replace("'", "''")}'");
                }
            }
            
            query.Append(string.Join(" AND ", whereClauses));
        }
        
        if (!string.IsNullOrEmpty(orderBy))
        {
            query.Append($" ORDER BY {orderBy}");
        }
        
        return query.ToString();
    }

    private static async Task<List<Dictionary<string, object>>> ExecuteQuery(
        string connectionString, 
        string query)
    {
        var results = new List<Dictionary<string, object>>();
        
        using (var connection = new SqlConnection(connectionString))
        {
            await connection.OpenAsync();
            
            using (var command = new SqlCommand(query, connection))
            {
                command.CommandTimeout = 30;
                
                using (var reader = await command.ExecuteReaderAsync())
                {
                    while (await reader.ReadAsync())
                    {
                        var row = new Dictionary<string, object>();
                        
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            string columnName = reader.GetName(i);
                            object value = reader.IsDBNull(i) ? null : reader.GetValue(i);
                            row[columnName] = value;
                        }
                        
                        results.Add(row);
                    }
                }
            }
        }
        
        return results;
    }

